package ui.employer;
import javax.swing.*;import javax.swing.table.*;import java.awt.*;import controller.*;import dao.*;import model.*;import util.*;import ui.common.TableStyle;
public class ApplicantsPanel extends JPanel{ JTable table=new JTable(); public ApplicantsPanel(){setBackground(UITheme.BG);setLayout(new BorderLayout());add(UITheme.title("Applicants"),BorderLayout.NORTH);add(new JScrollPane(table),BorderLayout.CENTER); JPanel b=UITheme.panel(); JButton sh=UITheme.button("Shortlist"); JButton re=UITheme.button("Reject"); b.add(sh);b.add(re);add(b,BorderLayout.SOUTH); sh.addActionListener(e->status(Constants.APP_SHORTLISTED)); re.addActionListener(e->status(Constants.APP_REJECTED)); load();} void load(){DefaultTableModel m=new DefaultTableModel(new Object[]{"Application ID","Internship ID","Student ID","Status","Applied At"},0); for(Application a:new ApplicationController().all())m.addRow(new Object[]{a.getId(),a.getJobId(),a.getStudentId(),a.getStatus(),a.getAppliedAt()}); table.setModel(m);TableStyle.apply(table);} void status(String s){int r=table.getSelectedRow(); if(r<0)return; int app=Integer.parseInt(table.getValueAt(r,0).toString()); int sid=Integer.parseInt(table.getValueAt(r,2).toString()); new ApplicationController().updateStatus(app,sid,s); load();}}
